code = """import json
import re

# Read the UC patents file
file_path = locals()['var_function-call-3522050226317471560']
with open(file_path, 'r') as f:
    uc_records = json.load(f)

uc_pub_nums = []
for rec in uc_records:
    info = rec['Patents_info']
    match = re.search(r'(?:publication|pub\.?)\s+(?:number|no\.)\s+([A-Z0-9-]+)', info)
    if match:
        uc_pub_nums.append(match.group(1))

# Construct SQL query
# SELECT Patents_info, citation, cpc FROM publicationinfo WHERE citation LIKE '%num1%' OR citation LIKE '%num2%' ...
# To be safe, use '%"publication_number": "NUM"%' to avoid partial matches if numbers are substrings of others
# But simpler: '%NUM%' is likely unique enough for patent numbers (e.g. US-123456-A1).
# I'll use '%NUM%'
conditions = [f"citation LIKE '%{num}%'" for num in uc_pub_nums]
where_clause = " OR ".join(conditions)
query = f"SELECT Patents_info, citation, cpc FROM publicationinfo WHERE {where_clause}"

print("__RESULT__:")
print(json.dumps(query))"""

